//! D.THINK.VOCABULARY.1 — The alphabet and its application.
//!
//! The 18 static generators are the alphabet. ComposedOperators are the words.
//! The compositor writes sentences from words. This module holds the alphabet:
//! the Thought enum, its application to grids, scoring, and the base vocabulary.
//!
//! Core Design Law 8: The alphabet stays fixed. The words grow.

/// A thought the system can form. Each variant produces an exact
/// rational matrix for a given grid geometry.
#[derive(Debug, Clone)]
pub enum Thought {
    /// Identity — no transformation. The null thought.
    Identity,
    /// Rotate 90° clockwise. Permutes cell indices.
    Rotate90,
    /// Rotate 180°.
    Rotate180,
    /// Rotate 270° (= 90° counterclockwise).
    Rotate270,
    /// Reflect across vertical axis.
    ReflectVertical,
    /// Reflect across horizontal axis.
    ReflectHorizontal,
    /// Translate by (Δrow, Δcol) with wrapping.
    Translate(i32, i32),
    /// Permute colors: color[i] → color[perm[i]].
    ColorPermute(Vec<usize>),
    /// Uniform additive shift: each cell += constant.
    UniformShift(i64),
    /// Per-cell additive change (the raw rule extracted from examples).
    CellChange(Vec<i64>),
    /// Composition of two thoughts: think A then think B.
    Compose(Box<Thought>, Box<Thought>),
    /// Tile a seed pattern across the row: detect repeating unit, extend.
    TilePattern,
    /// Replace each cell's value based on its distance from the nearest
    /// cell of a specific anchor color.
    DistanceFromColor(i64),
    /// For each cell of anchor_color, set cells at measured offsets to fill_color.
    /// The offsets are DERIVED from training data — the exact (dr, dc) displacement
    /// vectors from anchor to filled cells. Not a named pattern. The measurement.
    AdjacencyFill { anchor_color: i64, fill_color: i64, offsets: Vec<(i32, i32)> },
    /// Absolute target: output[cell] = targets[cell] regardless of input.
    AbsoluteTarget(Vec<i64>),
    /// Diagonal seed tile: extract non-zero objects, sort by diagonal position,
    /// map each unique value to its diagonal residue class, tile the grid.
    /// This is a FUNCTION of the input — different inputs produce different outputs.
    DiagonalSeedTile,
    /// Genomic operator: a composed operator from the state record, promoted to depth-1.
    /// These are EARNED words — proven by C(T) = 0 across training pairs.
    /// Core Design Law 8: the alphabet stays fixed, the words grow.
    /// The words enter the compositor as first-class generators.
    Genomic { opcode: u8, parameter: i64, sigma: Vec<(i16, i16)> },
}

impl Thought {
    /// The inverse element in the operator group.
    /// Every generator has an exact algebraic inverse.
    /// Compose(A, B)^{-1} = Compose(B^{-1}, A^{-1}).
    /// Core Design Law 8: the alphabet is fixed. The inverses are part of the algebra.
    pub fn inverse(&self) -> Thought {
        match self {
            Thought::Identity => Thought::Identity,
            Thought::Rotate90 => Thought::Rotate270,
            Thought::Rotate180 => Thought::Rotate180,
            Thought::Rotate270 => Thought::Rotate90,
            Thought::ReflectVertical => Thought::ReflectVertical,   // self-inverse
            Thought::ReflectHorizontal => Thought::ReflectHorizontal, // self-inverse
            Thought::Translate(dr, dc) => Thought::Translate(-dr, -dc),
            Thought::ColorPermute(perm) => {
                // Inverse permutation: inv[perm[i]] = i
                let mut inv = vec![0usize; perm.len()];
                perm.iter().enumerate().for_each(|(i, &p)| {
                    (p < inv.len()).then(|| inv[p] = i);
                });
                Thought::ColorPermute(inv)
            }
            Thought::UniformShift(k) => Thought::UniformShift(-k),
            Thought::CellChange(changes) => {
                Thought::CellChange(changes.iter().map(|c| -c).collect())
            }
            Thought::Compose(a, b) => {
                // (A then B)^{-1} = B^{-1} then A^{-1}
                Thought::Compose(Box::new(b.inverse()), Box::new(a.inverse()))
            }
            Thought::Genomic { opcode, parameter, sigma } => {
                // Inverse σ_post: swap (from, to) pairs
                let inv_sigma: Vec<(i16, i16)> = sigma.iter().map(|(s, t)| (*t, *s)).collect();
                Thought::Genomic { opcode: *opcode, parameter: -*parameter, sigma: inv_sigma }
            }
            // Non-invertible thoughts return identity — the group element is trivial
            _ => Thought::Identity,
        }
    }

    /// Produce the exact rational permutation/transformation for a grid.
    /// Returns the mapping: output_cell[i] = input_cell[map[i]].
    /// For value-level transforms, returns None (handled by apply_to_values).
    pub fn cell_mapping(&self, rows: usize, cols: usize) -> Option<Vec<usize>> {
        let n = rows * cols;
        match self {
            Thought::Identity => Some((0..n).collect()),
            Thought::Rotate90 => {
                // (r,c) → (c, rows-1-r)
                let mut map = vec![0; n];
                for r in 0..rows {
                    for c in 0..cols {
                        let src = r * cols + c;
                        let dst = c * rows + (rows - 1 - r);
                        if dst < n { map[dst] = src; }
                    }
                }
                Some(map)
            }
            Thought::Rotate180 => {
                let mut map = vec![0; n];
                for i in 0..n { map[i] = n - 1 - i; }
                Some(map)
            }
            Thought::Rotate270 => {
                // (r,c) → (cols-1-c, r)
                let mut map = vec![0; n];
                for r in 0..rows {
                    for c in 0..cols {
                        let src = r * cols + c;
                        let dst = (cols - 1 - c) * rows + r;
                        if dst < n { map[dst] = src; }
                    }
                }
                Some(map)
            }
            Thought::ReflectVertical => {
                // (r,c) → (r, cols-1-c)
                let mut map = vec![0; n];
                for r in 0..rows {
                    for c in 0..cols {
                        map[r * cols + (cols - 1 - c)] = r * cols + c;
                    }
                }
                Some(map)
            }
            Thought::ReflectHorizontal => {
                // (r,c) → (rows-1-r, c)
                let mut map = vec![0; n];
                for r in 0..rows {
                    for c in 0..cols {
                        map[(rows - 1 - r) * cols + c] = r * cols + c;
                    }
                }
                Some(map)
            }
            Thought::Translate(dr, dc) => {
                let mut map = vec![0; n];
                for r in 0..rows {
                    for c in 0..cols {
                        let nr = ((r as i32 + dr) % rows as i32 + rows as i32) as usize % rows;
                        let nc = ((c as i32 + dc) % cols as i32 + cols as i32) as usize % cols;
                        map[nr * cols + nc] = r * cols + c;
                    }
                }
                Some(map)
            }
            Thought::Compose(a, b) => {
                let map_a = a.cell_mapping(rows, cols)?;
                let map_b = b.cell_mapping(rows, cols)?;
                // Compose: first apply a, then b
                // output[i] = input[map_a[map_b[i]]]
                Some(map_b.iter().map(|&bi| map_a[bi]).collect())
            }
            // Genomic and other value-level transforms don't have cell mappings
            _ => None,
        }
    }

    /// Apply this thought to a flat grid of values.
    /// Returns the transformed grid.
    pub fn apply_to_values(&self, values: &[i64], rows: usize, cols: usize) -> Vec<i64> {
        match self {
            Thought::UniformShift(k) => values.iter().map(|v| v + k).collect(),
            Thought::CellChange(changes) => {
                values.iter().zip(changes.iter()).map(|(v, c)| v + c).collect()
            }
            Thought::ColorPermute(perm) => {
                values.iter().map(|&v| {
                    let idx = v as usize;
                    if idx < perm.len() { perm[idx] as i64 } else { v }
                }).collect()
            }
            Thought::AbsoluteTarget(targets) => targets.clone(),
            Thought::DiagonalSeedTile => {
                // Extract non-zero objects, sort by diagonal, compute seed via residue mapping
                let objects: Vec<(usize, usize, i64)> = (0..rows)
                    .flat_map(|r| (0..cols).map(move |c| (r, c, values[r * cols + c])))
                    .filter(|(_, _, v)| *v != 0)
                    .collect();
                if objects.is_empty() { return values.to_vec(); }
                let mut sorted = objects.clone();
                sorted.sort_by_key(|(r, c, _)| r + c);
                let mut unique_dpos: Vec<(i64, usize)> = Vec::new();
                for (r, c, v) in &sorted {
                    unique_dpos.iter().find(|(ev, _)| *ev == *v).is_none()
                        .then(|| unique_dpos.push((*v, r + c)));
                }
                let p = unique_dpos.len();
                if p == 0 { return values.to_vec(); }
                let mut seed = vec![0i64; p];
                for (v, dpos) in &unique_dpos { seed[dpos % p] = *v; }
                (0..rows * cols).map(|idx| {
                    seed[(idx / cols + idx % cols) % p]
                }).collect()
            },
            Thought::TilePattern => {
                // Detect seed from row 0, tile diagonally (shift by row index)
                let row0: Vec<i64> = values[0..cols].to_vec();
                let seed_len = row0.iter().position(|&v| v == 0).unwrap_or(cols);
                if seed_len > 0 && seed_len <= cols {
                    let seed = &row0[..seed_len];
                    let mut result = vec![0i64; values.len()];
                    for r in 0..rows {
                        for c in 0..cols {
                            // Diagonal: shift seed by row index
                            result[r * cols + c] = seed[(c + r) % seed_len];
                        }
                    }
                    result
                } else {
                    values.to_vec()
                }
            }
            Thought::DistanceFromColor(anchor) => {
                // Replace each cell with its Manhattan distance from nearest anchor cell
                let anchor_positions: Vec<(usize, usize)> = (0..rows)
                    .flat_map(|r| (0..cols).map(move |c| (r, c)))
                    .filter(|&(r, c)| values[r * cols + c] == *anchor)
                    .collect();
                let mut result = values.to_vec();
                for r in 0..rows {
                    for c in 0..cols {
                        if values[r * cols + c] == *anchor { continue; }
                        let min_dist = anchor_positions.iter()
                            .map(|&(ar, ac)| (r as i64 - ar as i64).abs() + (c as i64 - ac as i64).abs())
                            .min()
                            .unwrap_or(0);
                        if min_dist > 0 { result[r * cols + c] = min_dist; }
                    }
                }
                result
            }
            Thought::AdjacencyFill { anchor_color, fill_color, offsets } => {
                let mut result = values.to_vec();
                for r in 0..rows {
                    for c in 0..cols {
                        if values[r * cols + c] != *anchor_color { continue; }
                        // Fill at MEASURED offsets — derived from training data
                        for &(dr, dc) in offsets {
                            let nr = r as i32 + dr;
                            let nc = c as i32 + dc;
                            if nr >= 0 && nr < rows as i32 && nc >= 0 && nc < cols as i32 {
                                let idx = nr as usize * cols + nc as usize;
                                if result[idx] == 0 { result[idx] = *fill_color; }
                            }
                        }
                    }
                }
                result
            }
            Thought::Genomic { opcode, parameter, sigma } => {
                // Apply composed operator: spatial remap + σ_post value map
                crate::engine::SpatialPrimitive::from_opcode(*opcode)
                    .map(|prim| {
                        let background = values.iter().copied()
                            .max_by_key(|&v| values.iter().filter(|&&x| x == v).count())
                            .unwrap_or(0);
                        let ctx = crate::engine::SpatialContext {
                            param: *parameter, rows, cols, background,
                        };
                        (0..values.len()).map(|idx| {
                            let r = idx / cols;
                            let c = idx % cols;
                            let source_val = prim.map_position(r, c, &ctx)
                                .and_then(|(sr, sc)| {
                                    let si = sr * cols + sc;
                                    (si < values.len()).then(|| values[si])
                                })
                                .unwrap_or(values[idx]);
                            sigma.iter()
                                .find(|(sv, _)| *sv == source_val as i16)
                                .map(|(_, tv)| *tv as i64)
                                .unwrap_or(source_val)
                        }).collect()
                    })
                    .unwrap_or_else(|| values.to_vec())
            }
            Thought::Compose(a, b) => {
                // Group product: apply A first, then B to the result.
                // This works for ALL thought types — value-level, spatial, mixed.
                let after_a = a.apply_to_values(values, rows, cols);
                b.apply_to_values(&after_a, rows, cols)
            }
            _ => {
                // Spatial transforms: use cell mapping
                if let Some(map) = self.cell_mapping(rows, cols) {
                    map.iter().map(|&src| values.get(src).copied().unwrap_or(0)).collect()
                } else {
                    values.to_vec()
                }
            }
        }
    }

    /// Human-readable name for this thought.
    pub fn name(&self) -> String {
        match self {
            Thought::Identity => "identity".into(),
            Thought::Rotate90 => "rotate_90".into(),
            Thought::Rotate180 => "rotate_180".into(),
            Thought::Rotate270 => "rotate_270".into(),
            Thought::ReflectVertical => "reflect_v".into(),
            Thought::ReflectHorizontal => "reflect_h".into(),
            Thought::Translate(dr, dc) => format!("translate({},{})", dr, dc),
            Thought::ColorPermute(_) => "color_permute".into(),
            Thought::UniformShift(k) => format!("shift({})", k),
            Thought::CellChange(_) => "cell_change".into(),
            Thought::Compose(a, b) => format!("{}∘{}", a.name(), b.name()),
            Thought::TilePattern => "tile_pattern".into(),
            Thought::DistanceFromColor(c) => format!("dist_from_{}", c),
            Thought::AdjacencyFill { anchor_color, fill_color, .. } =>
                format!("adj_fill_{}→{}", anchor_color, fill_color),
            Thought::AbsoluteTarget(_) => "absolute_target".into(),
            Thought::DiagonalSeedTile => "diagonal_seed_tile".into(),
            Thought::Genomic { opcode, parameter, .. } => format!("genomic({},{})", opcode, parameter),
        }
    }
}

