// THINK.2 — The Thinking Process
// ═══════════════════════════════════════════════════════════════════════

/// Result of thinking about a puzzle.
#[derive(Debug, Clone)]
pub struct ThinkingResult {
    /// The thought that best explains the observation.
    pub best_thought: Thought,
    /// Distance: 0 = perfect understanding.
    pub distance: u64,
    /// Was understanding achieved? (distance = 0)
    pub understood: bool,
    /// How many thoughts were evaluated.
    pub thoughts_evaluated: u32,
    /// Composition depth of the best thought.
    pub depth: u32,
}

/// Generate the base vocabulary of thoughts for a given grid geometry.
///
/// The irreducible algebraic alphabet. Fewer letters, deeper words.
/// Rotate180 = Rotate90², Rotate270 = Rotate90³ — discoverable by composition.
/// Translations beyond ±1 — discoverable by composing Translate(1,0) twice.
/// AdjacencyFill — parameterized, populated by derive_algebraic_properties().
///
/// The compositor reaches depth 6 with this reduced alphabet.
/// Each depth level compounds on the previous. The effective vocabulary
/// is exponential in depth, not linear in alphabet size.
pub fn base_vocabulary(rows: usize, cols: usize) -> Vec<Thought> {
    let mut vocab = vec![
        Thought::Identity,
        Thought::ReflectVertical,
        Thought::ReflectHorizontal,
    ];

    // Rotate90 generates {Rotate90, Rotate180, Rotate270} through composition
    // Only meaningful for square grids
    if rows == cols {
        vocab.push(Thought::Rotate90);
    }

    // Immediate neighbor translations — compose for distance > 1
    for dr in -1i32..=1 {
        for dc in -1i32..=1 {
            if dr == 0 && dc == 0 { continue; }
            vocab.push(Thought::Translate(dr, dc));
        }
    }

    // Uniform shifts: small shifts are common transformations.
    // ±4, ±5 discoverable by composition from these.
    for k in -3i64..=3 {
        if k == 0 { continue; }
        vocab.push(Thought::UniformShift(k));
    }

    // Color permutations: each transposition is algebraically irreducible.
    // The transpositions generate the full symmetric group through composition.
    for a in 0..5usize {
        for b in (a + 1)..5 {
            let mut perm: Vec<usize> = (0..10).collect();
            perm[a] = b;
            perm[b] = a;
            vocab.push(Thought::ColorPermute(perm));
        }
    }

    // Structural thoughts
    vocab.push(Thought::TilePattern);
    vocab.push(Thought::DiagonalSeedTile);

    // Distance-based coloring — parameterized by anchor
    for anchor in 1..=9i64 {
        vocab.push(Thought::DistanceFromColor(anchor));
    }

    // AdjacencyFill: parameterized type. Offsets populated by measurement.
    // Reduced to anchor colors 1-3 — the compositor composes the rest.
    for anchor in 1..=3i64 {
        for fill in 1..=5i64 {
            if fill != anchor {
                vocab.push(Thought::AdjacencyFill {
                    anchor_color: anchor, fill_color: fill,
                    offsets: vec![],
                });
            }
        }
    }

    vocab
}

/// Value-level vocabulary: thoughts that transform VALUE relationships.
/// These operate on the outermost manifold (k unique colors, k~10 dimensions).
/// ColorPermute, UniformShift — the value algebra.
pub fn value_vocabulary() -> Vec<Thought> {
    let mut vocab = vec![Thought::Identity];

    // Uniform shifts: value translation
    for k in -3i64..=3 {
        if k == 0 { continue; }
        vocab.push(Thought::UniformShift(k));
    }

    // Color permutations: value permutation group
    for a in 0..5usize {
        for b in (a + 1)..5 {
            let mut perm: Vec<usize> = (0..10).collect();
            perm[a] = b;
            perm[b] = a;
            vocab.push(Thought::ColorPermute(perm));
        }
    }

    vocab
}

/// Object-level vocabulary: thoughts that transform SPATIAL relationships.
/// These operate on the middle manifold (n objects, n~10 dimensions).
/// Rotate, Reflect, Translate — the spatial algebra.
pub fn object_vocabulary(rows: usize, cols: usize) -> Vec<Thought> {
    let mut vocab = vec![Thought::Identity];

    // Rotation (square grids)
    if rows == cols {
        vocab.push(Thought::Rotate90);
    }

    // Reflections
    vocab.push(Thought::ReflectVertical);
    vocab.push(Thought::ReflectHorizontal);

    // Translations: immediate neighbors
    for dr in -1i32..=1 {
        for dc in -1i32..=1 {
            if dr == 0 && dc == 0 { continue; }
            vocab.push(Thought::Translate(dr, dc));
        }
    }

    vocab
}

/// Cell-level vocabulary: thoughts that operate on individual grid positions.
/// These operate on the innermost manifold (rows × cols dimensions).
/// TilePattern, AdjacencyFill, DistanceFromColor, DiagonalSeedTile.
pub fn cell_vocabulary() -> Vec<Thought> {
    let mut vocab = vec![Thought::Identity];

    vocab.push(Thought::TilePattern);
    vocab.push(Thought::DiagonalSeedTile);

    for anchor in 1..=9i64 {
        vocab.push(Thought::DistanceFromColor(anchor));
    }

    for anchor in 1..=3i64 {
        for fill in 1..=5i64 {
            if fill != anchor {
                vocab.push(Thought::AdjacencyFill {
                    anchor_color: anchor, fill_color: fill,
                    offsets: vec![],
                });
            }
        }
    }

    vocab
}

/// Measure how well a thought explains a training pair.
///
/// D.SCORE.COHESION.2 — Cohesion-aware scoring for the compositor.
/// Primary: category-level cocycle residual in Z (relational coherence).
/// Secondary: L1 cell distance (positional refinement).
///
/// The cocycle residual measures whether the predicted transformation
/// preserves the relational structure of the target. A rotation that
/// moves every cell but preserves all value-category relationships
/// scores zero on the primary component. The compositor keeps it alive.
///
/// O(k³) where k = unique values. i64. No Q. Core Design Law IV.
pub(crate) fn thought_score(thought: &Thought, input: &[i64], output: &[i64], rows: usize, cols: usize) -> (u64, Vec<i64>) {
    let predicted = thought.apply_to_values(input, rows, cols);
    let n = input.len().min(output.len()).min(predicted.len());

    // L1 cell distance — positional refinement (secondary)
    let l1: u64 = (0..n).map(|i| (predicted[i] - output[i]).unsigned_abs()).sum();

    // Category-level cocycle residual — relational cohesion (primary)
    // 1. Collect unique values from input
    let mut unique_vals: Vec<i64> = Vec::new();
    for &v in input {
        if !unique_vals.contains(&v) { unique_vals.push(v); }
    }
    unique_vals.sort();
    let k = unique_vals.len();

    // 2. Build target category map: input_val[i] → dominant output_val
    let mut target_cats: Vec<i64> = Vec::with_capacity(k);
    for &sv in &unique_vals {
        let mut counts: Vec<(i64, usize)> = Vec::new();
        for idx in 0..n {
            if input[idx] == sv {
                let tv = output[idx];
                let entry = counts.iter_mut().find(|(v, _)| *v == tv);
                match entry {
                    Some(e) => e.1 += 1,
                    None => counts.push((tv, 1)),
                }
            }
        }
        target_cats.push(counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv));
    }

    // 3. Build candidate category map: input_val[i] → dominant predicted_val
    let mut cand_cats: Vec<i64> = Vec::with_capacity(k);
    for &sv in &unique_vals {
        let mut counts: Vec<(i64, usize)> = Vec::new();
        for idx in 0..n {
            if input[idx] == sv {
                let dv = predicted[idx];
                let entry = counts.iter_mut().find(|(v, _)| *v == dv);
                match entry {
                    Some(e) => e.1 += 1,
                    None => counts.push((dv, 1)),
                }
            }
        }
        cand_cats.push(counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv));
    }

    // 4. Cocycle residual of (T_candidate - T_target) across all triples in Z
    let mut cocycle_residual: u64 = 0;
    for i in 0..k {
        for j in 0..k {
            if j == i { continue; }
            for ki in 0..k {
                if ki == i || ki == j { continue; }
                let t_ik = (target_cats[ki] - target_cats[i]) as i64;
                let t_ij = (target_cats[j] - target_cats[i]) as i64;
                let t_jk = (target_cats[ki] - target_cats[j]) as i64;
                let c_ik = (cand_cats[ki] - cand_cats[i]) as i64;
                let c_ij = (cand_cats[j] - cand_cats[i]) as i64;
                let c_jk = (cand_cats[ki] - cand_cats[j]) as i64;
                let diff_ik = c_ik - t_ik;
                let diff_ij = c_ij - t_ij;
                let diff_jk = c_jk - t_jk;
                let r = diff_ik - diff_ij - diff_jk;
                cocycle_residual += r.unsigned_abs();
            }
        }
    }

    // Cohesion primary, L1 secondary. Scale cocycle by n so it dominates.
    let total = cocycle_residual * (n as u64) + l1;
    (total, predicted)
}
